import{_ as o,o as e,c as s,a2 as r}from"./chunks/framework.jisAoZJG.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/packages.html"}]]},"headers":[],"relativePath":"packages.md","filePath":"packages.md"}'),t={name:"packages.md"};function i(n,a,l,c,d,g){return e(),s("div",null,[...a[0]||(a[0]=[r('<h2 id="package-structure" tabindex="-1">Package Structure <a class="header-anchor" href="#package-structure" aria-label="Permalink to &quot;Package Structure&quot;">​</a></h2><p>Below is a full breakdown of all <strong>Core</strong>, <strong>Feature</strong>, <strong>Experimental</strong>, and <strong>Utility</strong> packages available in SQLRooms. Each package can be installed independently via <code>pnpm add @sqlrooms/&lt;name&gt;</code> and mixed‑and‑matched to suit your app&#39;s needs.</p><h3 id="core-packages" tabindex="-1">Core Packages <a class="header-anchor" href="#core-packages" aria-label="Permalink to &quot;Core Packages&quot;">​</a></h3><ul><li><strong><a href="/api/artifacts/">@sqlrooms/artifacts</a></strong> — Artifact registry, workspace tab helpers, and layout integration for dashboards, notebooks, documents, canvases, pivots, and apps.</li><li><strong><a href="/api/blocks/">@sqlrooms/blocks</a></strong> — Shared block contracts and vocabulary for composable SQLRooms blocks and block containers.</li><li><strong><a href="/api/room-config/">@sqlrooms/room-config</a></strong> — Zod schemas and types for persisted room configuration.</li><li><strong><a href="/api/room-shell/">@sqlrooms/room-shell</a></strong> — Central application shell and Zustand‑based state manager with panel system and DuckDB integration.</li><li><strong><a href="/api/core/">@sqlrooms/room-store</a></strong> — Core state management utilities, RoomStore, and React context providers.</li><li><strong><a href="/api/duckdb/">@sqlrooms/duckdb</a></strong> — WebAssembly build of DuckDB plus helper hooks for query execution and data import.</li><li><strong><a href="/api/duckdb-core/">@sqlrooms/duckdb-core</a></strong> — Shared DuckDB connector contracts and core query/import utilities.</li><li><strong><a href="/api/duckdb-node/">@sqlrooms/duckdb-node</a></strong> — Node.js DuckDB connector for server-side SQLRooms runtimes.</li><li><strong><a href="/api/db/">@sqlrooms/db</a></strong> — DuckDB-centered orchestration layer for multi-database execution.</li><li><strong><a href="/api/db-settings/">@sqlrooms/db-settings</a></strong> — Database connection settings state and UI components.</li><li><strong><a href="/api/ui/">@sqlrooms/ui</a></strong> — Tailwind‑powered component library and theme manager used across all other packages.</li><li><strong><a href="/api/ai/">@sqlrooms/ai</a></strong> — Natural‑language querying and AI‑assisted analytics tools.</li><li><strong><a href="/api/ai-config/">@sqlrooms/ai-config</a></strong> — Zod schemas and defaults for persisted AI slice configuration.</li><li><strong><a href="/api/ai-core/">@sqlrooms/ai-core</a></strong> — Lower-level AI slice, chat UI primitives, and tool-streaming utilities.</li><li><strong><a href="/api/ai-settings/">@sqlrooms/ai-settings</a></strong> — AI provider/model settings state and UI components.</li><li><strong><a href="/api/layout/">@sqlrooms/layout</a></strong> — Panel layout management built on react‑mosaic.</li><li><strong><a href="/api/layout-config/">@sqlrooms/layout-config</a></strong> — Zod schemas and types for persisted layout configuration.</li></ul><h3 id="feature-packages" tabindex="-1">Feature Packages <a class="header-anchor" href="#feature-packages" aria-label="Permalink to &quot;Feature Packages&quot;">​</a></h3><ul><li><strong><a href="/api/cells/">@sqlrooms/cells</a></strong> — Shared cells model and UI primitives used by notebook and canvas views.</li><li><strong><a href="/api/codemirror/">@sqlrooms/codemirror</a></strong> — CodeMirror 6 editor components with SQLRooms theme integration and JSON/JavaScript editing helpers.</li><li><strong><a href="/api/color-scales/">@sqlrooms/color-scales</a></strong> — Color-scale config, validation, legend models, and React legend components.</li><li><strong><a href="/api/cosmos/">@sqlrooms/cosmos</a></strong> — High‑performance WebGL graph visualization with Cosmos.</li><li><strong><a href="/api/data-table/">@sqlrooms/data-table</a></strong> — Interactive data grid for SQL results with sorting and pagination.</li><li><strong><a href="/api/deck/">@sqlrooms/deck</a></strong> — Deck.gl map integration with JSON-driven map specs and DuckDB/Arrow dataset binding.</li><li><strong><a href="/api/documents/">@sqlrooms/documents</a></strong> — Markdown document artifacts, structured BlockDocument/Worksheet surfaces, rich editors, document assets, and document CRDT sync.</li><li><strong><a href="/api/dropzone/">@sqlrooms/dropzone</a></strong> — Drag‑and‑drop file uploads with type validation and progress tracking.</li><li><strong><a href="/api/kepler/">@sqlrooms/kepler</a></strong> — Kepler.gl integration for map-first SQLRooms analytics experiences.</li><li><strong><a href="/api/kepler-config/">@sqlrooms/kepler-config</a></strong> — Zod schemas for persisted Kepler slice state.</li><li><strong><a href="/api/monaco-editor/">@sqlrooms/monaco-editor</a></strong> — VS Code&#39;s Monaco editor with SQL‑aware autocompletion.</li><li><strong><a href="/api/mosaic/">@sqlrooms/mosaic</a></strong> — Declarative charting powered by UW IDL&#39;s Mosaic library.</li><li><strong><a href="/api/motherduck/">@sqlrooms/motherduck</a></strong> — MotherDuck connector using the WASM client</li><li><strong><a href="/api/recharts/">@sqlrooms/recharts</a></strong> — Responsive charts via Recharts (line, bar, pie, etc.).</li><li><strong><a href="/api/s3-browser/">@sqlrooms/s3-browser</a></strong> — S3‑compatible storage browser with uploads and directory management.</li><li><strong><a href="/api/s3-browser-config/">@sqlrooms/s3-browser-config</a></strong> — Zod schemas for persisted S3 browser configuration.</li><li><strong><a href="/api/schema-tree/">@sqlrooms/schema-tree</a></strong> — Interactive database‑schema explorer.</li><li><strong><a href="/api/sql-editor/">@sqlrooms/sql-editor</a></strong> — SQL editor with history, syntax highlighting, and result docking.</li><li><strong><a href="/api/sql-editor-config/">@sqlrooms/sql-editor-config</a></strong> — Zod schemas and defaults for persisted SQL editor state.</li><li><strong><a href="/api/vega/">@sqlrooms/vega</a></strong> — Vega‑Lite visualization components for sophisticated interactive charts.</li></ul><h3 id="experimental-packages" tabindex="-1">Experimental Packages <a class="header-anchor" href="#experimental-packages" aria-label="Permalink to &quot;Experimental Packages&quot;">​</a></h3><ul><li><strong><a href="/api/ai-rag/">@sqlrooms/ai-rag</a></strong> — Retrieval-augmented generation slice for semantic search over DuckDB-backed embeddings.</li><li><strong><a href="/api/canvas/">@sqlrooms/canvas</a></strong> — React Flow-based artifact canvas for SQL, Vega, and dataflow node DAGs.</li><li><strong><a href="/api/crdt/">@sqlrooms/crdt</a></strong> — Loro-backed CRDT slice, persistence, and sync helpers.</li><li><strong><a href="/api/discuss/">@sqlrooms/discuss</a></strong> — Threaded discussion system with anchor links to data points.</li><li><strong><a href="/api/notebook/">@sqlrooms/notebook</a></strong> — Artifact-scoped notebook UI and state slice for SQL, text, Markdown, Vega, and input cells.</li><li><strong><a href="/api/pivot/">@sqlrooms/pivot</a></strong> — Slice-driven pivot table UI backed by DuckDB SQL and Vega-Lite charts.</li><li><strong><a href="/api/webcontainer/">@sqlrooms/webcontainer</a></strong> — WebContainer state slice and runtime helpers for app-building workflows.</li></ul><h3 id="utility-packages" tabindex="-1">Utility Packages <a class="header-anchor" href="#utility-packages" aria-label="Permalink to &quot;Utility Packages&quot;">​</a></h3><ul><li><strong><a href="/api/utils/">@sqlrooms/utils</a></strong> — Shared helper functions for colors, formatting, random IDs, and string utilities.</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2>',11)])])}const h=o(t,[["render",i]]);export{m as __pageData,h as default};
